from sys import stdin, stdout
from collections import defaultdict

class Solution:
  def solve(self):
    orders = defaultdict(list)
    for line in stdin:
      customer_id, order_id = line.split()
      orders[customer_id].append(order_id)
    for customer_id, order_ids in orders.items():
      stdout.write(f'{customer_id} {len(order_ids)}
')
